using System;
using System.Linq;
using System.Threading.Tasks;
using Microsoft.EntityFrameworkCore;

public class EventBookingContext : DbContext
{
    public DbSet<Seat> Seats { get; set; }

    protected override void OnConfiguring(DbContextOptionsBuilder optionsBuilder)
    {
        optionsBuilder.UseSqlServer("YourConnectionStringHere");
    }
}

public class Seat
{
    public int Id { get; set; }
    public bool IsAvailable { get; set; }
}

public class EventBookingService
{
    private readonly EventBookingContext _context;

    public EventBookingService(EventBookingContext context)
    {
        _context = context;
    }

    public async Task<bool> PurchaseTickets(int seatId, int quantity)
    {
        var seats = await _context.Seats.Where(s => s.Id == seatId && s.IsAvailable).Take(quantity).ToListAsync();

        if (seats.Count != quantity)
        {
            return false; // Not enough available seats
        }

        foreach (var seat in seats)
        {
            seat.IsAvailable = false;
        }

        await _context.SaveChangesAsync();

        return true;
    }
}